 21	import { TimeControl } from '../../components/Time/TimeControl';
 22	import { EnvoyDetails } from 'components/Envoy/EnvoyDetails';
 23	import { WorkloadHealth } from 'types/Health';
 24	import { RenderHeader } from '../../components/Nav/Page/RenderHeader';
 25	import { ErrorSection } from '../../components/ErrorSection/ErrorSection';
 26	import { ErrorMsg } from '../../types/ErrorMsg';
 27	import { connectRefresh } from '../../components/Refresh/connectRefresh';
 28	import { HistoryManager } from 'app/History';
 29	import { basicTabStyle } from 'styles/TabStyles';
 30	import { ZtunnelConfig } from '../../components/Ambient/ZtunnelConfig';
 31	import { WaypointConfig } from '../../components/Ambient/WaypointConfig';
 32	import { isGVKSupported } from '../../utils/IstioConfigUtils';
 33	
 34	type WorkloadDetailsState = {
 35	  cluster?: string;
 36	  currentTab: string;
 37	  error?: ErrorMsg;
 38	  health?: WorkloadHealth;
 39	  waypointServiceFilter?: string;
 40	  workload?: Workload;
 41	};
 42	
 43	type ReduxProps = {
 44	  duration: DurationInSeconds;
 45	  rangeDuration: TimeRange;
 46	  tracingInfo?: TracingInfo;
 47	};
 48	
 49	type WorkloadDetailsPageProps = ReduxProps & {
 50	  lastRefreshAt: TimeInMilliseconds;
 51	  workloadId: WorkloadId;
 52	};
 53	
 54	export const tabName = 'tab';
 55	export const defaultTab = 'info';
 56	export const istioProxyName = 'istio-proxy';
 57	
 58	const paramToTab: { [key: string]: number } = {
 59	  info: 0,
 60	  traffic: 1,
 61	  logs: 2,
 62	  in_metrics: 3,
 63	  out_metrics: 4,
 64	  traces: 5,
 65	  waypoint: 7,
 66	  ztunnel: 8
 67	};
 68	
 69	let nextTabIndex = 6;
 70	
 71	class WorkloadDetailsPageComponent extends React.Component<WorkloadDetailsPageProps, WorkloadDetailsState> {
 72	  constructor(props: WorkloadDetailsPageProps) {
 73	    super(props);
 74	    const cluster = HistoryManager.getClusterName();
 75	    this.state = { currentTab: activeTab(tabName, defaultTab), cluster: cluster };
 76	  }
 77	
 78	  componentDidMount(): void {
 79	    this.fetchWorkload();
 80	  }
 81	
 82	  componentDidUpdate(prevProps: WorkloadDetailsPageProps): void {
 83	    // when linking from one cluster's workload to another cluster's workload, cluster in state should be changed
 84	    const cluster = HistoryManager.getClusterName() ?? this.state.cluster;
 85	    const currentTab = activeTab(tabName, defaultTab);
 86	
 87	    const mustFetch =
 88	      cluster !== this.state.cluster ||
 89	      this.props.workloadId.namespace !== prevProps.workloadId.namespace ||
 90	      this.props.workloadId.workload !== prevProps.workloadId.workload ||
 91	      this.props.lastRefreshAt !== prevProps.lastRefreshAt ||
 92	      this.props.duration !== prevProps.duration;
 93	
 94	    if (mustFetch || currentTab !== this.state.currentTab) {
 95	      if (
 96	        mustFetch ||
 97	        currentTab === 'envoy' ||
 98	        currentTab === 'info' ||
 99	        currentTab === 'logs' ||
100	        currentTab === 'waypoint' ||
101	        currentTab === 'ztunnel'
102	      ) {
103	        this.fetchWorkload(cluster).then(() => {
104	          this.setState({ currentTab: currentTab, cluster: cluster });
105	        });
106	      } else {
107	        this.setState({ currentTab: currentTab, cluster: cluster });
108	      }
109	    }
110	    // @TODO set the cluster in tab url
111	    //HistoryManager.setParam(URLParam.CLUSTER, this.state.cluster);
112	  }
113	
114	  private fetchWorkload = async (cluster?: string): Promise<void> => {
115	    if (!cluster) {
116	      cluster = this.state.cluster;
117	    }
118	
119	    const params: WorkloadQuery = {
120	      validate: 'true',
121	      rateInterval: `${String(this.props.duration)}s`,
122	      health: 'true'
123	    };
124	
125	    return API.getWorkload(this.props.workloadId.namespace, this.props.workloadId.workload, params, cluster)
126	      .then(details => {
127	        if (details.data.services && details.data.services.length > 0) {
128	          this.setState({ waypointServiceFilter: details.data.services[0].name });
129	        }
130	
131	        this.setState({
132	          workload: details.data,
133	          health: WorkloadHealth.fromJson(
134	            this.props.workloadId.namespace,
135	            this.props.workloadId.workload,
136	            details.data.health,
137	            {
138	              rateInterval: this.props.duration,
139	              hasSidecar: details.data.istioSidecar,
140	              hasAmbient: details.data.isAmbient
141	            }
142	          )
143	        });
144	      })
145	      .catch(error => {
146	        AlertUtils.addError('Could not fetch Workload.', error);
147	
148	        const msg: ErrorMsg = {
149	          title: 'No Workload is selected',
150	          description: `${this.props.workloadId.workload} is not found in the mesh`
151	        };
152	
153	        this.setState({ error: msg });
154	      });
155	  };
156	
157	  private staticTabs(): React.ReactNode[] {
158	    const hasPods = this.state.workload?.pods.length;
159	    const tabsArray: React.ReactNode[] = [];
160	
161	    const overTab = (
162	      <Tab title="Overview" eventKey={0} key="Overview">
163	        <WorkloadInfo
164	          workload={this.state.workload}
165	          duration={this.props.duration}
166	          health={this.state.health}
167	          namespace={this.props.workloadId.namespace}
168	          refreshWorkload={this.fetchWorkload}
169	        />
170	      </Tab>
171	    );
172	    tabsArray.push(overTab);
173	
174	    if (this.state.workload && isGVKSupported(this.state.workload.gvk)) {
175	      const trafficTab = (
176	        <Tab title="Traffic" eventKey={1} key="Traffic">
177	          <TrafficDetails
178	            itemName={this.props.workloadId.workload}
179	            itemType={MetricsObjectTypes.WORKLOAD}
180	            lastRefreshAt={this.props.lastRefreshAt}
181	            namespace={this.props.workloadId.namespace}
182	            cluster={this.state.cluster}
183	          />
184	        </Tab>
185	      );
186	      tabsArray.push(trafficTab);
187	
188	      if (!serverConfig.kialiFeatureFlags.disabledFeatures?.includes('logs-tab')) {
189	        const logTab = (
190	          <Tab title="Logs" eventKey={2} key="Logs" data-test="workload-details-logs-tab">
191	            {hasPods ? (
192	              <WorkloadPodLogs
193	                lastRefreshAt={this.props.lastRefreshAt}
194	                namespace={this.props.workloadId.namespace}
195	                workload={this.props.workloadId.workload}
196	                pods={this.state.workload!.pods}
197	                cluster={this.state.cluster}
198	                waypoints={this.state.workload!.waypointWorkloads}
199	                waypointServiceFilter={this.state.waypointServiceFilter}
200	              />
201	            ) : (
202	              <EmptyState variant={EmptyStateVariant.full}>
203	                <EmptyStateHeader
204	                  titleText={<>No logs for Workload{this.props.workloadId.workload}</>}
205	                  headingLevel="h5"
206	                />
207	                <EmptyStateBody>There are no logs to display because the workload has no pods.</EmptyStateBody>
208	              </EmptyState>
209	            )}
210	          </Tab>
211	        );
212	        tabsArray.push(logTab);
213	      }
214	
215	      const inTab = (
216	        <Tab title="Inbound Metrics" eventKey={3} key="Inbound Metrics">
217	          <IstioMetrics
218	            data-test="inbound-metrics-component"
219	            direction="inbound"
220	            includeAmbient={!!this.state.workload?.isAmbient}
221	            lastRefreshAt={this.props.lastRefreshAt}
222	            namespace={this.props.workloadId.namespace}
223	            object={this.props.workloadId.workload}
224	            cluster={this.state.cluster}
225	            objectType={MetricsObjectTypes.WORKLOAD}
226	          />
227	        </Tab>
228	      );
229	      tabsArray.push(inTab);
230	
231	      const outTab = (
232	        <Tab title="Outbound Metrics" eventKey={4} key="Outbound Metrics">
233	          <IstioMetrics
234	            data-test="outbound-metrics-component"
235	            direction="outbound"
236	            includeAmbient={!!this.state.workload?.isAmbient}
237	            lastRefreshAt={this.props.lastRefreshAt}
238	            namespace={this.props.workloadId.namespace}
239	            object={this.props.workloadId.workload}
240	            cluster={this.state.cluster}
241	            objectType={MetricsObjectTypes.WORKLOAD}
242	          />
243	        </Tab>
244	      );
245	      tabsArray.push(outTab);
246	
247	      if (this.props.tracingInfo && this.props.tracingInfo.enabled && this.props.tracingInfo.integration) {
248	        const fromWaypoint =
249	          this.state.workload?.waypointWorkloads && this.state.workload.waypointWorkloads.length > 0 ? true : false;
250	        tabsArray.push(
251	          <Tab eventKey={5} title="Traces" key="Traces">
252	            <TracesComponent
253	              lastRefreshAt={this.props.lastRefreshAt}
254	              namespace={this.props.workloadId.namespace}
255	              cluster={this.state.cluster}
256	              target={this.props.workloadId.workload}
257	              targetKind="workload"
258	              fromWaypoint={fromWaypoint}
259	              waypointServiceFilter={this.state.waypointServiceFilter}
260	            />
261	          </Tab>
262	        );
263	      }
264	    }
265	
266	    if (this.state.workload && (this.hasIstioSidecars(this.state.workload) || this.state.workload.isWaypoint)) {
267	      const envoyTab = (
268	        <Tab title="Envoy" eventKey={10} key="Envoy">
269	          {this.state.workload && (
270	            <EnvoyDetails
271	              lastRefreshAt={this.props.lastRefreshAt}
272	              namespace={this.props.workloadId.namespace}
273	              workload={this.state.workload}
274	            />
275	          )}
276	        </Tab>
277	      );
278	      tabsArray.push(envoyTab);
279	      paramToTab['envoy'] = 10;
280	    }
281	
282	    if (this.state.workload && this.state.workload.isZtunnel) {
283	      const ztunnelTab = (
284	        <Tab title="Ztunnel" eventKey={11} key="Ztunnel">
285	          {this.state.workload && (
286	            <ZtunnelConfig
287	              lastRefreshAt={this.props.lastRefreshAt}
288	              namespace={this.props.workloadId.namespace}
289	              rangeDuration={this.props.rangeDuration}
290	              workload={this.state.workload}
291	            />
292	          )}
293	        </Tab>
294	      );
295	      tabsArray.push(ztunnelTab);
296	      paramToTab['ztunnel'] = 11;
297	    }
298	
299	    if (this.state.workload && this.state.workload.isWaypoint) {
300	      const waypointTab = (
301	        <Tab title="Waypoint" eventKey={12} key="Waypoint">
302	          {this.state.workload && <WaypointConfig workload={this.state.workload} />}
303	        </Tab>
304	      );
305	      tabsArray.push(waypointTab);
306	      paramToTab['waypoint'] = 12;
307	    }
308	
309	    // Used by the runtimes tabs
310	    nextTabIndex = tabsArray.length + 1;
311	
312	    return tabsArray;
313	  }
314	
315	  private hasIstioSidecars(workload: Workload): boolean {
316	    let hasIstioSidecars = false;
317	
318	    if (workload.pods.length > 0) {
319	      workload.pods.forEach(pod => {
320	        if (pod.istioContainers && pod.istioContainers.length > 0) {
321	          hasIstioSidecars = true;
322	        } else if (pod.istioInitContainers && pod.istioInitContainers.some(cont => cont.name === istioProxyName)) {
323	          hasIstioSidecars = true;
324	        } else {
325	          // Ztunnel doesn't have Envoy
326	          hasIstioSidecars =
327	            hasIstioSidecars ||
328	            (!!pod.containers && pod.containers.some(cont => cont.name === istioProxyName && !workload.isZtunnel));
329	        }
330	      });
331	    }
332	
333	    return hasIstioSidecars;
334	  }
335	
336	  private runtimeTabs(): React.ReactNode[] {
337	    const tabs: React.ReactNode[] = [];
338	
339	    if (this.state.workload) {
340	      const appLabelName = getAppLabelName(this.state.workload.labels);
341	      const verLabelName = getVersionLabelName(this.state.workload.labels);
342	      const app = appLabelName ? this.state.workload.labels[appLabelName] : undefined;
343	      const version = verLabelName ? this.state.workload.labels[verLabelName] : undefined;
344	      const isLabeled = app && version;
345	
346	      if (isLabeled) {
347	        let tabOffset = 0;
348	        this.state.workload.runtimes.forEach(runtime => {
349	          runtime.dashboardRefs.forEach(dashboard => {
350	            if (dashboard.template !== 'envoy') {
351	              const tabKey = tabOffset + nextTabIndex;
352	              paramToTab[dashboard.template] = tabKey;
353	
354	              const tab = (
355	                <Tab key={dashboard.template} title={dashboard.title} eventKey={tabKey}>
356	                  <CustomMetrics
357	                    app={app}
358	                    appLabelName={appLabelName}
359	                    lastRefreshAt={this.props.lastRefreshAt}
360	                    namespace={this.props.workloadId.namespace}
361	                    template={dashboard.template}
362	                    version={version}
363	                    versionLabelName={verLabelName}
364	                    workload={this.state.workload!.name}
365	                    workloadType={this.state.workload!.gvk.Kind}
366	                  />
367	                </Tab>
368	              );
369	
370	              tabs.push(tab);
371	              tabOffset++;
372	            }
373	          });
374	        });
375	      }
376	    }
377	
378	    return tabs;
379	  }
380	
381	  private renderTabs(): React.ReactNode[] {
382	    // PF4 Tabs doesn't support static tabs followed of an array of tabs created dynamically.
383	    return this.staticTabs().concat(this.runtimeTabs());
384	  }
385	
386	  render(): React.ReactNode {
387	    // set default to true: all dynamic tabs (unlisted below) are for runtimes dashboards, which uses custom time
388	    let useCustomTime = true;
389	
390	    switch (this.state.currentTab) {
391	      case 'info':
392	      case 'traffic':
393	        useCustomTime = false;
394	        break;
395	      case 'in_metrics':
396	      case 'out_metrics':
397	      case 'logs':
398	      case 'traces':
399	        useCustomTime = true;
400	        break;
401	    }
402	
403	    const actionsToolbar =
404	      this.state.currentTab === 'info' && this.state.workload ? (
405	        <WorkloadWizardDropdown
406	          namespace={this.props.workloadId.namespace}
407	          workload={this.state.workload}
408	          onChange={this.fetchWorkload}
409	        />
410	      ) : undefined;
411	
412	    return (
413	      <>
414	        <RenderHeader rightToolbar={<TimeControl customDuration={useCustomTime} />} actionsToolbar={actionsToolbar} />
415	
416	        {this.state.error && <ErrorSection error={this.state.error} />}
417	
418	        {this.state.workload && (
419	          <ParameterizedTabs
420	            id="basic-tabs"
421	            className={basicTabStyle}
422	            onSelect={tabValue => {
423	              this.setState({ currentTab: tabValue, cluster: this.state.cluster });
424	            }}
425	            tabMap={paramToTab}
426	            tabName={tabName}
427	            defaultTab={defaultTab}
428	            activeTab={this.state.currentTab}
429	            mountOnEnter={true}
430	            unmountOnExit={true}
431	          >
432	            {this.renderTabs()}
433	          </ParameterizedTabs>
434	        )}
435	      </>
436	    );
437	  }
438	}
439	
440	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
441	  duration: durationSelector(state),
442	  rangeDuration: timeRangeSelector(state),
443	  tracingInfo: state.tracingState.info
444	});
445	
446	export const WorkloadDetailsPage = connectRefresh(connect(mapStateToProps)(WorkloadDetailsPageComponent));

